`timescale 1ns / 1ps
 
module testbench_labtest2_combinational;
 
    integer count;
    
    // ------------------ Specify variables generated by testbench ------------------ 
    reg[3:0] in1, in2, in3, in4;
	reg in5, in6, in7, in8;
    
    // ------------------ Specify variables that are watched by testbench ------------------ 
    wire[3:0] out1, out2;
	wire out3, out4;
    
    labtest_q2_hardware myname(.a(in1),.b(in2),
                                .c(in5),.d(in3),
                                .x(out1),.y(out3));
 
    // ------------------ Setup inputs ------------------
    // Provide initial values for inputs. The ‘initial’ command
    // is only valid within the testbench.
    // Can use this for all simple testbenches
    initial begin 
        count = 0;
    end
 
    always begin
        #50
        count=count+1;
    end
 
    // Toggle inputs at different rates to cover all input  
    always @(count) begin
        case (count)
            1 : begin in1<=4'b0111; in2<=4'b1111; in5<=1'b0; in4<=4'b0101; end 
            default : begin in1<=4'b0000; in2<=4'b0000; in5<=1'b0;  in4<=4'b0000; end 
        endcase
    end
 

initial begin
        count = 0;
        $dumpfile("testbench2.vcd");
        $dumpvars(0, testbench_labtest2_combinational);
        #500 $finish;
    end
endmodule
